  options = '[{"id":"A","text":"highlight the geographical significance of Alaska.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"provide evidence of the long history of interaction between cultures.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"show that the Bering Strait is a narrow body of water.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"describe the methods that Indigenous people use to cross the Bering Strait.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The details about the Bering Strait most likely function to provide evidence of the long history of interaction between cultures. The text states that for centuries, Indigenous people from both sides of the Bering Strait traveled between Alaska and Russia, which demonstrates that the two cultures have a long history of interaction. The other choices are not supported by the text. The Bering Strait’s geographical significance is not the main focus of the text, and the details about the Bering Strait’s width and the methods used by Indigenous people to cross the strait are not the main points of the text. The passage states that "Although most of the United States is located on the North American continent, parts of Alaska are in Asia. These parts …", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: provide evidence of the long history of interaction between cultures.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":1216,"opensat_domain":"Standard English Conventions","opensat_raw_id":"6a578c7d","opensat_difficulty":"Medium","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.916Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
